const items = $input.all();

function norm(s) {
  if (s === null || s === undefined) return '';
  return String(s)
    .toLowerCase()
    .replace(/—С/g, '–µ')
    .replace(/[^\p{L}\p{N}\s/+.-]/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tokenize(text) {
  return norm(text)
    .split(/\s+/)
    .map(t => t.trim())
    .filter(Boolean);
}

function splitTerms(text) {
  if (!text) return [];

  const stop = new Set([
    '–Љ–≥', '–Љ–ї', '–≥', '–Ї–≥', 'ml', 'mg', 'n', 'na', 'cl', 'ca', 'k', 'd',
    '–Є', '–Є–ї–Є', '–і–ї—П', '–њ—А–Є', '–њ–Њ–і', '–љ–∞–і', '–±–µ–Ј', '–Њ—В', '–і–Њ', '–њ–Њ',
    '—Б—А–µ–і—Б—В–≤–Њ', '—Б—А–µ–і—Б—В–≤–∞', '—Д–Њ—А–Љ–∞', '—Д–Њ—А–Љ—Л', '–і–µ—В–Є', '–≤–Ј—А–Њ—Б–ї—Л–µ'
  ]);

  return Array.from(new Set(
    norm(text)
      .split(/[\/,;|()+]+/)
      .flatMap(part => part.split(/\s+/))
      .map(s => s.trim())
      .filter(Boolean)
      .filter(t => t.length >= 3)
      .filter(t => !/^\d+$/.test(t))
      .filter(t => !stop.has(t))
  ));
}

function hasAnyWord(text, words) {
  if (!words || !words.length) return false;
  const tokens = new Set(tokenize(text).filter(w => w.length >= 3));
  return words.some(w => tokens.has(norm(w)));
}

function routeHints(text) {
  const t = norm(text);
  return {
    oral: /(—Б–Є—А–Њ–њ|—В–∞–±–ї–µ—В|–Ї–∞–њ—Б—Г–ї|–Ї–∞–њ—Б\.|–њ–∞—Б—В–Є–ї|–ї–µ–і–µ–љ—Ж|–њ–Њ—А–Њ—И–Њ–Ї|—Б—Г—Б–њ–µ–љ–Ј|–≤–љ—Г—В—А—М|–Њ—А–∞–ї—М–љ)/.test(t),
    nasal: /(–љ–∞–Ј–∞–ї|–≤ –љ–Њ—Б|–Ї–∞–њ–ї–Є –≤ –љ–Њ—Б|—Б–њ—А–µ–є –≤ –љ–Њ—Б)/.test(t),
    throat: /(–≥–Њ—А–ї–Њ|—Б–њ—А–µ–є –і–ї—П –≥–Њ—А–ї–∞|–њ–∞—Б—В–Є–ї|–ї–µ–і–µ–љ—Ж)/.test(t),
    eye: /(–≥–ї–∞–Ј|–≥–ї–∞–Ј–љ)/.test(t),
    skin: /(–Ї—А–µ–Љ|–Љ–∞–Ј|–≥–µ–ї—М|–ї–Њ—Б—М–Њ–љ|—Б—Л–≤–Њ—А–Њ—В–Ї|–Љ–∞—Б–Ї–∞|–њ–µ–љ–Ї–∞|—И–∞–Љ–њ—Г–љ—М|—Д–ї—О–Є–і|–±–∞–ї—М–Ј–∞–Љ)/.test(t),
    external: /(–љ–∞—А—Г–ґ|–Љ–µ—Б—В–љ|–Ї—А–µ–Љ|–Љ–∞–Ј|–≥–µ–ї—М|–ї–Њ—Б—М–Њ–љ|—Б—Л–≤–Њ—А–Њ—В–Ї|–Љ–∞—Б–Ї–∞|–њ–µ–љ–Ї–∞|—И–∞–Љ–њ—Г–љ—М|—Д–ї—О–Є–і|–±–∞–ї—М–Ј–∞–Љ)/.test(t),
    infusion: /(–Є–љ—Д—Г–Ј|—А-—А –і\/–Є–љ—Д—Г–Ј|—А–∞—Б—В–≤–Њ—А –і\/–Є–љ—Д—Г–Ј|–≤\/–≤)/.test(t),
    injection: /(–∞–Љ–њ—Г–ї|–Є–љ—К–µ–Ї—Ж|—И–њ—А–Є—Ж)/.test(t),
  };
}

function ageHints(text) {
  const t = norm(text);
  return {
    child: /(–і–µ—В|baby|kid|junior|–Љ–∞–ї—Л—И|–Љ–ї–∞–і–µ–љ|0\+|1\+|2\+|3\+)/.test(t),
    adult: /(–≤–Ј—А–Њ—Б–ї)/.test(t),
  };
}

function guessProductType(text) {
  const t = norm(text);

  if (/(–њ–Њ–і–≥—Г–Ј–љ–Є–Ї|—В—А—Г—Б–Є–Ї–Є-–њ–Њ–і–≥—Г–Ј–љ–Є–Ї–Є|—В—А—Г—Б–Є–Ї–Є –њ–Њ–і–≥—Г–Ј–љ–Є–Ї–Є|—В—А—Г—Б–Є–Ї–Є|–њ–∞–Љ–њ–µ—А—Б)/.test(t)) return 'infant_hygiene';
  if (/(–њ—А–Њ–Ї–ї–∞–і–Ї|—В–∞–Љ–њ–Њ–љ|–µ–ґ–µ–і–љ–µ–≤–Ї)/.test(t)) return 'female_hygiene';

  if (/(—И–∞–Љ–њ—Г–љ—М|–њ–µ–љ–Ї–∞|–≥–µ–ї—М –і\/—Г–Љ—Л–≤–∞–љ–Є—П|—Г–Љ—Л–≤–∞–љ|–ї–Њ—Б—М–Њ–љ|–Љ–∞—Б–Ї–∞ –і\/–ї–Є—Ж–∞|—Б—Л–≤–Њ—А–Њ—В–Ї|–Ї—А–µ–Љ –і\/—А—Г–Ї|–Ї—А–µ–Љ –і\/–ї–Є—Ж–∞|–Ї—А–µ–Љ –і–ї—П —А—Г–Ї|–Ї—А–µ–Љ –і–ї—П –ї–Є—Ж–∞|—Г–≤–ї–∞–ґ–љ—П—О—Й|—Б–Њ–ї–љ—Ж–µ–Ј–∞—Й–Є—В–љ|—Д–ї—О–Є–і|–Ї–Њ—Б–Љ–µ—В–Є—З–µ—Б–Ї)/.test(t)) {
    return 'cosmetic';
  }

  if (/(—И–њ—А–Є—Ж|–Є–≥–ї|–Ї–∞—В–µ—В–µ—А|—В–µ—Б—В[- ]?–њ–Њ–ї–Њ—Б–Ї|—В–µ—Б—В —Б–Є—Б—В–µ–Љ–∞|–Љ–µ–ґ–њ–∞–ї—М—Ж–µ–≤—Л–є —А–∞–Ј–і–µ–ї–Є—В–µ–ї—М|–Њ—А—В–Њ–њ–µ–і|–±–Є–љ—В|–њ–ї–∞—Б—В—Л—А|–Є–љ–≥–∞–ї—П—В–Њ—А|—В–µ—А–Љ–Њ–Љ–µ—В—А)/.test(t)) {
    return 'device';
  }

  if (/(–≤–Є—В–∞–Љ–Є–љ|–±–µ—В–∞-–Ї–∞—А–Њ—В–Є–љ|–±–µ—В–∞ –Ї–∞—А–Њ—В–Є–љ|—Б–њ–Є—А—Г–ї–Є–љ|–±–∞–і|now foods|–љ–∞—Г —Д—Г–і—Б)/.test(t)) return 'supplement';

  if (/(—А-—А –і\/–Є–љ—Д—Г–Ј|–Є–љ—Д—Г–Ј–Є|–љ–∞—В—А–Є—П —Е–ї–Њ—А–Є–і|–∞–Љ–њ—Г–ї|–Є–љ—К–µ–Ї—Ж)/.test(t)) return 'infusion_drug';

  if (/(—В–∞–±\.|—В–∞–±–ї–µ—В|–Ї–∞–њ—Б—Г–ї|—Б–Є—А–Њ–њ|—Б—Г—Б–њ–µ–љ–Ј|–њ–Њ—А–Њ—И–Њ–Ї|–і—А–∞–ґ–µ)/.test(t)) return 'drug';

  if (/(–Ј–∞–Ї–≤–∞—Б–Ї|—Б–Љ–µ—В–∞–љ|–є–Њ–≥—Г—А—В|–Ї–µ—Д–Є—А)/.test(t)) return 'food';

  return 'other';
}

function looksLikeCosmeticCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const dir = norm(c.direction);
  return (
    code.startsWith('COSM_') ||
    /–Ї–Њ—Б–Љ–µ—В|—Г—Е–Њ–і|–ї–Є—Ж–∞|—А—Г–Ї|—В–µ–ї–∞|–≤–Њ–ї–Њ—Б|—И–∞–Љ–њ—Г–љ|—Б—Л–≤–Њ—А–Њ—В|–Љ–∞—Б–Ї–∞|–њ–µ–љ–Ї–∞|–≥–Є–≥–Є–µ–љ/.test(name) ||
    /–Ї–Њ—Б–Љ–µ—В|—Г—Е–Њ–і|–≥–Є–≥–Є–µ–љ/.test(dir)
  );
}

function looksLikeInfantHygieneCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  return code.startsWith('FAM_CAT_INFANT') || /–њ–Њ–і–≥—Г–Ј–љ–Є–Ї|—В—А—Г—Б–Є–Ї–Є/.test(name);
}

function looksLikeFemaleHygieneCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  return (
    code.startsWith('COSM_CAT_HYGIENE') ||
    /–њ—А–Њ–Ї–ї–∞–і–Ї|—В–∞–Љ–њ–Њ–љ|–µ–ґ–µ–і–љ–µ–≤–Ї/.test(name) ||
    /–≥–Є–≥–Є–µ–љ–Є—З–µ—Б–Ї–Є–µ –ґ–µ–љ—Б–Ї–Є–µ/.test(name)
  );
}

function looksLikeDeviceCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const dir = norm(c.direction);
  return (
    code.startsWith('LS_MD_') ||
    /—И–њ—А–Є—Ж|–Є–≥–ї|—В–µ—Б—В|–Њ—А—В–Њ–њ–µ–і|—Б—В–µ–ї—М–Ї|—А–∞–Ј–і–µ–ї–Є—В–µ–ї|–±–Є–љ—В|–њ–ї–∞—Б—В—Л—А|–Є–љ—Б—В—А—Г–Љ–µ–љ—В/.test(name) ||
    /–Љ–µ–і–Є—Ж–Є–љ—Б–Ї/.test(dir)
  );
}

function looksLikeSupplementCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const dir = norm(c.direction);
  return (
    code.startsWith('BA_') ||
    /–≤–Є—В–∞–Љ–Є–љ|–Љ–Є–љ–µ—А–∞–ї|–Ї–Њ–Љ–њ–ї–µ–Ї—Б|–Є–Љ–Љ—Г–љ|–±–∞–і|—Б–њ–Є—А—Г–ї–Є–љ|–Ї–∞—А–Њ—В–Є–љ/.test(name) ||
    /–±–∞–і/.test(dir)
  );
}

function looksLikeInfusionDrugCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  const name = norm(c.category_name);
  const mnn = norm(c.mnn_cluster);
  return (
    code.startsWith('LS_INF_') ||
    /–Є–љ—Д—Г–Ј|—А–∞—Б—В–≤–Њ—А|—А–µ–≥–Є–і—А–Њ–љ|—А–Є–љ–≥–µ—А|–љ–∞—В—А–Є—П|—Е–ї–Њ—А–Є–і/.test(name) ||
    /–љ–∞—В—А–Є—П|—Е–ї–Њ—А–Є–і|–Є–љ—Д—Г–Ј/.test(mnn)
  );
}

function looksLikeDrugCategory(c) {
  const code = (c.category_code || '').toUpperCase();
  return code.startsWith('LS_') && !code.startsWith('LS_MD_') && !code.startsWith('LS_INF_');
}

const products = [];
const categories = [];

for (const item of items) {
  const j = item.json;

  if ('product_raw_id' in j) {
    products.push({
      product_id: j.product_id ?? j.id ?? null,
      product_raw_id: j.product_raw_id ?? null,
      product_name_effective: j.product_name_effective ?? null,
      manufacturer_effective: j.manufacturer_effective ?? null,
      brand_guess: j.brand_guess ?? null,
      form_guess: j.form_guess ?? null,
      dosage_guess: j.dosage_guess ?? null,
      pack_size_guess: j.pack_size_guess ?? null,
      combined_text: j.combined_text ?? null
    });
  } else if ('category_code' in j) {
    categories.push(j);
  }
}

const out = [];

for (const p of products) {
  const baseText = norm([
    p.product_name_effective,
    p.manufacturer_effective,
    p.brand_guess,
    p.form_guess,
    p.dosage_guess,
    p.pack_size_guess,
    p.combined_text
  ].filter(Boolean).join(' '));

  const productTypeGuess = guessProductType(baseText);
  const rh = routeHints(baseText);
  const ah = ageHints(baseText);

  const scored = [];

  for (const c of categories) {
    const catCode = (c.category_code || '').toUpperCase();

    if (productTypeGuess === 'cosmetic' && !looksLikeCosmeticCategory(c)) continue;
    if (productTypeGuess === 'infant_hygiene' && !looksLikeInfantHygieneCategory(c)) continue;
    if (productTypeGuess === 'female_hygiene' && !looksLikeFemaleHygieneCategory(c)) continue;
    if (productTypeGuess === 'device' && !looksLikeDeviceCategory(c)) continue;
    if (productTypeGuess === 'supplement' && !looksLikeSupplementCategory(c)) continue;
    if (productTypeGuess === 'infusion_drug' && !looksLikeInfusionDrugCategory(c)) continue;
    if (productTypeGuess === 'drug' && !looksLikeDrugCategory(c)) continue;
    if (productTypeGuess === 'food') continue;

    let score = 0;
    const reasons = [];

    const categoryTerms = splitTerms(c.category_name);
    const nosologyTerms = splitTerms(c.need_nosology);
    const mnnTerms = splitTerms(c.mnn_cluster);
    const commentTerms = splitTerms(c.inclusion_comment).filter(t => t.length >= 5);

    const ageSegment = norm(c.age_segment);
    const route = norm(c.administration_route);

    for (const term of categoryTerms) {
      if (term && baseText.includes(term)) {
        score += 7;
        reasons.push(`category:${term}`);
      }
    }

    for (const term of nosologyTerms) {
      if (term && baseText.includes(term)) {
        score += 5;
        reasons.push(`nosology:${term}`);
      }
    }

    for (const term of mnnTerms) {
      if (term && baseText.includes(term)) {
        score += 6;
        reasons.push(`mnn:${term}`);
      }
    }

    for (const term of commentTerms.slice(0, 8)) {
      if (term && baseText.includes(term)) {
        score += 2;
        reasons.push(`comment:${term}`);
      }
    }

    if (hasAnyWord(baseText, c.include_keywords || [])) {
      score += 10;
      reasons.push('include_keywords');
    }

    if (hasAnyWord(baseText, c.exclude_keywords || [])) {
      score -= 12;
      reasons.push('exclude_keywords');
    }

    if (ageSegment.includes('–і–µ—В') && ah.child) {
      score += 4;
      reasons.push('age:child');
    }
    if (ageSegment.includes('–≤–Ј—А–Њ—Б') && ah.adult) {
      score += 4;
      reasons.push('age:adult');
    }

    if (route.includes('–љ–∞–Ј–∞–ї') && rh.nasal) {
      score += 5;
      reasons.push('route:nasal');
    }
    if (route.includes('–≤–љ—Г—В—А—М') && rh.oral) {
      score += 4;
      reasons.push('route:oral');
    }
    if (route.includes('–Њ—А–Њ—Д–∞—А') && rh.throat) {
      score += 5;
      reasons.push('route:throat');
    }
    if (route.includes('–љ–∞—А—Г–ґ') && rh.external) {
      score += 3;
      reasons.push('route:external');
    }
    if (route.includes('–≥–ї–∞–Ј') && rh.eye) {
      score += 5;
      reasons.push('route:eye');
    }

    if (productTypeGuess === 'infusion_drug' && rh.infusion && catCode.startsWith('LS_INF_')) {
      score += 8;
      reasons.push('product_type:infusion_drug');
    }

    if (productTypeGuess === 'device' && catCode.startsWith('LS_MD_')) {
      score += 5;
      reasons.push('product_type:device');
    }

    if (productTypeGuess === 'supplement' && catCode.startsWith('BA_')) {
      score += 6;
      reasons.push('product_type:supplement');
    }

    if (productTypeGuess === 'cosmetic' && catCode.startsWith('COSM_')) {
      score += 6;
      reasons.push('product_type:cosmetic');
    }

    const hasStrongMatch =
      reasons.some(r => r.startsWith('category:')) ||
      reasons.some(r => r.startsWith('nosology:')) ||
      reasons.some(r => r.startsWith('mnn:')) ||
      reasons.some(r => r.startsWith('comment:')) ||
      reasons.includes('include_keywords') ||
      reasons.includes('product_type:infusion_drug') ||
      reasons.includes('product_type:device') ||
      reasons.includes('product_type:supplement') ||
      reasons.includes('product_type:cosmetic');

    if (!hasStrongMatch) {
      score = 0;
    }

    if (score > 0) {
      scored.push({
        category_id: String(c.id),
        category_code: c.category_code,
        category_name: c.category_name,
        score,
        reasons
      });
    }
  }

  scored.sort((a, b) => b.score - a.score);

  out.push({
    json: {
      product_id: p.product_id ?? null,
      product_raw_id: p.product_raw_id,
      product_name_effective: p.product_name_effective,
      manufacturer_effective: p.manufacturer_effective,
      combined_text: p.combined_text,
      product_type_guess: productTypeGuess,
      shortlist: scored.slice(0, 5),
      top_category_id: scored[0]?.category_id ?? null,
      top_category_name: scored[0]?.category_name ?? null,
      top_score: scored[0]?.score ?? 0,
      shortlist_count: scored.length
    }
  });
}

return out;
